import React from 'react';
import ReactDOM from 'react-dom';
import './index.css';
import App from './App';
import * as serviceWorker from './serviceWorker';

ReactDOM.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>,
  document.getElementById('root')
);

serviceWorker.unregister();

import React from 'react';
import './App.css';

function App() {
  return (
    <div className="App">
      <h1>Welcome to My React App!</h1>
      <p>This is a sample React application.</p>
    </div>
  );
}

export default App;

import React from 'react';
import './header.css';

function Header() {
  return (
    <header>
      <h2>Welcome to My React App</h2>
    </header>
  );
}

export default Header;

import React from 'react';
import './footer.css';

function Footer() {
  return (
    <footer>
      <p>© 2021 My React App. All rights reserved.</p>
    </footer>
  );
}

export default Footer;

import React from 'react';
import './sidebar.css';

function Sidebar() {
  return (
    <div className="sidebar">
      <ul>
        <li>Home</li>
        <li>About</li>
        <li>Services</li>
        <li>Contact</li>
      </ul>
    </div>
  );
}

export default Sidebar;

